<?php
namespace App\Notifications;use Illuminate\Bus\Queueable;use Illuminate\Notifications\Messages\MailMessage;use Illuminate\Notifications\Notification;
class ParticipantEmailChangeVerification extends Notification{use Queueable;public function __construct(public readonly string $token,public readonly string $newEmail){}public function via(object $notifiable):array{return['mail'];}public function toMail(object $notifiable):MailMessage{return(new MailMessage)->subject('Neue E-Mail-Adresse für Matrix bestätigen')->greeting('E-Mail-Adresse bestätigen')->line('Für Ihr Matrix-Teilnehmerkonto wurde eine neue E-Mail-Adresse angefordert.')->action('E-Mail-Adresse bestätigen',route('participant-portal.contact.email.confirm',$this->token))->line('Der Link ist 60 Minuten gültig. Wenn Sie die Änderung nicht angefordert haben, ignorieren Sie diese Nachricht.');}public function routeNotificationForMail(object $notifiable):string{return$this->newEmail;}}
